import { NextRequest, NextResponse } from 'next/server';
import { scheduleEmail } from '@/lib/scheduler';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, subject, message, scheduledTime } = body;

    if (!email || !subject || !message || !scheduledTime) {
      return NextResponse.json(
        { error: 'Lütfen tüm alanları doldurun.' },
        { status: 400 }
      );
    }

    const date = new Date(scheduledTime);
    if (isNaN(date.getTime())) {
      return NextResponse.json(
        { error: 'Geçersiz tarih formatı.' },
        { status: 400 }
      );
    }

    if (date < new Date()) {
      return NextResponse.json(
        { error: 'Geçmiş bir zamana planlama yapılamaz.' },
        { status: 400 }
      );
    }

    const taskId = scheduleEmail(email, subject, message, date);

    return NextResponse.json({
      success: true,
      message: 'E-posta başarıyla planlandı.',
      taskId,
      scheduledTime: date.toLocaleString()
    });
  } catch (error: any) {
    console.error('Planlama hatası:', error);
    return NextResponse.json(
      { error: 'E-posta planlanırken bir hata oluştu.' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth } from "@/lib/authMiddleware";
import { startOfDay, subDays, endOfDay } from "date-fns";

export async function GET(req: NextRequest) {
  try {
    const payload = await requireAuth(req);
    if (payload instanceof NextResponse) return payload;

    const accountId = payload.accountId;

    // 1. Stock Status Summary
    const ingredients = await prisma.ingredient.findMany({
      where: { accountId },
      select: {
        id: true,
        name: true,
        currentStock: true,
        minStockLevel: true,
        unit: true,
      },
    });

    const totalItems = ingredients.length;
    const criticalItems = ingredients.filter(
      (i) => i.currentStock <= i.minStockLevel
    );
    const criticalCount = criticalItems.length;

    // 2. Consumption Trend (Last 7 Days)
    const sevenDaysAgo = startOfDay(subDays(new Date(), 6));

    const transactions = await prisma.stockTransaction.findMany({
      where: {
        accountId,
        type: { in: ["OUT", "WASTE"] },
        createdAt: { gte: sevenDaysAgo },
      },
      include: {
        ingredient: {
          select: { name: true, unit: true }
        }
      }
    });

    // Group transactions by date
    const dailyConsumption: Record<string, number> = {};
    for (let i = 0; i < 7; i++) {
      const dateStr = subDays(new Date(), i).toISOString().split('T')[0];
      dailyConsumption[dateStr] = 0;
    }

    transactions.forEach(t => {
      const dateStr = t.createdAt.toISOString().split('T')[0];
      if (dailyConsumption[dateStr] !== undefined) {
        dailyConsumption[dateStr] += t.quantity;
      }
    });

    const trendData = Object.entries(dailyConsumption)
      .map(([date, amount]) => ({
        date: date.split('-').slice(1).join('/'), // MM/DD format
        amount
      }))
      .reverse();

    // 3. Top Consumed Items (Last 30 Days)
    const thirtyDaysAgo = startOfDay(subDays(new Date(), 30));
    const topTransactions = await prisma.stockTransaction.groupBy({
      by: ['ingredientId'],
      where: {
        accountId,
        type: { in: ["OUT", "WASTE"] },
        createdAt: { gte: thirtyDaysAgo },
      },
      _sum: {
        quantity: true
      },
      orderBy: {
        _sum: {
          quantity: 'desc'
        }
      },
      take: 5
    });

    const topMovingItems = await Promise.all(
      topTransactions.map(async (t) => {
        const ingredient = await prisma.ingredient.findUnique({
          where: { id: t.ingredientId },
          select: { name: true, unit: true }
        });
        return {
          name: ingredient?.name || "Bilinmiyor",
          amount: t._sum.quantity || 0,
          unit: ingredient?.unit || ""
        };
      })
    );

    // 4. Distribution Data (Current Stock vs Min for critical or all)
    const distributionData = ingredients
      .slice(0, 8) // Limit to avoid clutter
      .map(i => ({
        name: i.name,
        current: i.currentStock,
        min: i.minStockLevel
      }));

    return NextResponse.json({
      summary: {
        totalItems,
        criticalCount,
        normalCount: totalItems - criticalCount,
        topMovingItem: topMovingItems[0]?.name || "N/A"
      },
      trend: trendData,
      topMoving: topMovingItems,
      distribution: distributionData
    });
  } catch (error) {
    console.error("Analytics Error:", error);
    return NextResponse.json({ error: "Failed to fetch analytics" }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth } from "@/lib/authMiddleware";

export async function PATCH(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const payload = await requireAuth(req);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const { id: idStr } = await params;
    const id = parseInt(idStr);
    const body = await req.json();
    const { name, minStockLevel, unit } = body;

    // Kaynağı check et - kullanıcı bu kaynağı kullanabilir mi?
    const ingredient = await prisma.ingredient.findUnique({
      where: { id },
    });

    if (!ingredient || ingredient.accountId !== payload.accountId) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    const updated = await prisma.ingredient.update({
      where: { id },
      data: {
        name,
        unit,
        minStockLevel: parseFloat(minStockLevel),
      },
    });

    // Activity Log
    try {
      await prisma.activityLog.create({
        data: {
          action: "UPDATE",
          ingredientId: id,
          ingredientName: updated.name,
          details: `Ad: ${name}, Birim: ${unit}, Min: ${minStockLevel}`,
          accountId: payload.accountId,
        },
      });
    } catch (e) {
      console.error("Log error (Update):", e);
    }

    return NextResponse.json(updated);
  } catch (error: any) {
    console.error("Update Error:", error);
    return NextResponse.json({ error: "Update failed", details: error.message }, { status: 500 });
  }
}

export async function DELETE(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  try {
    const payload = await requireAuth(req);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const { id: idStr } = await params;
    const id = parseInt(idStr);

    const ingredient = await prisma.ingredient.findUnique({ where: { id } });

    if (!ingredient) return NextResponse.json({ error: "Not found" }, { status: 404 });
    if (ingredient.accountId !== payload.accountId) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    // Activity Log - FIRST, so we have the info
    try {
      await prisma.activityLog.create({
        data: {
          action: "DELETE",
          ingredientId: null,
          ingredientName: ingredient.name,
          details: "Malzeme tamamen silindi",
          accountId: payload.accountId,
        },
      });
    } catch (e) {
      console.error("Log error (Delete):", e);
    }

    // Explicitly delete transactions
    await prisma.stockTransaction.deleteMany({
      where: { ingredientId: id },
    });

    await prisma.ingredient.delete({
      where: { id },
    });

    return NextResponse.json({ success: true });
  } catch (error: any) {
    console.error("Delete Error:", error);
    return NextResponse.json({ error: "Delete failed", details: error.message }, { status: 500 });
  }
}

import { prisma } from "@/lib/prisma";
import { NextResponse, NextRequest } from "next/server";
import { requireAuth } from "@/lib/authMiddleware";

export async function GET(request: NextRequest) {
  try {
    const payload = await requireAuth(request);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const ingredients = await prisma.ingredient.findMany({
      where: {
        accountId: payload.accountId,
      },
      orderBy: { name: 'asc' }
    });
    return NextResponse.json(ingredients);
  } catch (error) {
    console.error("GET Ingredients Error:", error);
    return NextResponse.json({ error: "Failed to fetch ingredients" }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const payload = await requireAuth(req);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const body = await req.json();
    const { name, unit, minStockLevel, currentStock } = body;

    if (!name || !unit) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    console.log("Creating ingredient with data:", { name, unit, minStockLevel, currentStock });

    const ingredient = await prisma.ingredient.create({
      data: {
        name,
        unit,
        minStockLevel: parseFloat(minStockLevel) || 0,
        currentStock: parseFloat(currentStock) || 0,
        accountId: payload.accountId,
      },
    });

    // Activity Log
    await prisma.activityLog.create({
      data: {
        action: "CREATE",
        ingredientId: ingredient.id,
        ingredientName: ingredient.name,
        quantity: ingredient.currentStock,
        details: "İlk stok oluşturuldu",
        accountId: payload.accountId,
      },
    });

    return NextResponse.json(ingredient);
  } catch (error: any) {
    console.error("POST Ingredient Error Detailed:", error);
    return NextResponse.json({ 
      error: "Failed to create ingredient", 
      details: error.message || "Unknown error" 
    }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth } from "@/lib/authMiddleware";

export async function GET(req: NextRequest) {
  try {
    const payload = await requireAuth(req);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const { searchParams } = new URL(req.url);
    const limitParam = searchParams.get("limit") || "20";
    const isAll = limitParam === "all";
    const limit = isAll ? 0 : parseInt(limitParam);
    const page = parseInt(searchParams.get("page") || "1");
    const search = searchParams.get("search") || "";
    const action = searchParams.get("action") || "";

    const skip = isAll ? undefined : (page - 1) * limit;
    const take = isAll ? undefined : limit;

    const where: any = {
      accountId: payload.accountId,
    };
    if (search) {
      where.ingredientName = { contains: search };
    }
    if (action && action !== "ALL") {
      where.action = action;
    }

    const [logs, total] = await Promise.all([
      prisma.activityLog.findMany({
        where,
        orderBy: { createdAt: "desc" },
        skip,
        take,
      }),
      prisma.activityLog.count({ where }),
    ]);

    return NextResponse.json({
      logs,
      total,
      page,
      totalPages: Math.ceil(total / limit),
    });
  } catch (error: any) {
    return NextResponse.json({ error: "Failed to fetch logs" }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from "next/server";
import { prisma } from "@/lib/prisma";
import { requireAuth } from "@/lib/authMiddleware";
import { sendLowStockEmail } from "@/lib/email";

export async function POST(req: NextRequest) {
  try {
    const payload = await requireAuth(req);

    if (payload instanceof NextResponse) {
      return payload;
    }

    const body = await req.json();
    const { ingredientId: idRaw, type, quantity, note } = body;
    const ingredientId = parseInt(idRaw);

    if (!ingredientId || !type || quantity === undefined) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    // Atomic transaction: Create movement record AND update ingredient stock
    const result = await prisma.$transaction(async (tx) => {
      // 1. Get current ingredient and check stock
      const current = await tx.ingredient.findUnique({
        where: { id: ingredientId },
      });

      // Fetch users belonging to this account to send them emails
      const users = await tx.user.findMany({
        where: { accountId: payload.accountId },
        select: { email: true }
      });

      if (!current || users.length === 0) {
        throw new Error("Ingredient or Users not found");
      }

      const userEmails = users.map(u => u.email).filter(Boolean).join(", ");

      // Check authorization
      if (current.accountId !== payload.accountId) {
        throw new Error("Unauthorized");
      }

      // Calculate new stock level
      // IN increases stock, OUT and WASTE decrease it
      const multiplier = type === "IN" ? 1 : -1;
      const stockChange = parseFloat(quantity) * multiplier;
      const newStock = current.currentStock + stockChange;

      // Prevent negative stock
      if (newStock < 0) {
        throw new Error("Yetersiz stok! Stok miktarı sıfırın altına düşemez.");
      }

      // 2. Create the transaction record
      const transaction = await tx.stockTransaction.create({
        data: {
          ingredientId,
          type,
          quantity: parseFloat(quantity),
          note,
          accountId: payload.accountId,
        },
      });

      // 3. Update ingredient stock
      const updatedIngredient = await tx.ingredient.update({
        where: { id: ingredientId },
        data: {
          currentStock: newStock,
        },
      });

      // 4. Add Activity Log
      await tx.activityLog.create({
        data: {
          action: type, // IN, OUT, WASTE
          ingredientId,
          ingredientName: updatedIngredient.name,
          quantity: parseFloat(quantity),
          details: note || `${type} işlemi yapıldı`,
          accountId: payload.accountId,
        },
      });

      const emailNeeded = (type === "OUT" || type === "WASTE") && current.currentStock > current.minStockLevel && newStock <= current.minStockLevel;
      console.log(`[Email Debug] type: ${type}, oldStock: ${current.currentStock}, newStock: ${newStock}, min: ${current.minStockLevel}, needed: ${emailNeeded}`);

      return { 
        transaction, 
        updatedIngredient,
        targetEmails: userEmails,
        emailNeeded
      };
    });

    console.log(`[Email Debug] Outside transaction. emailNeeded=${result.emailNeeded}, targetEmails=${result.targetEmails}`);
    if (result.emailNeeded && result.targetEmails) {
      console.log(`[Email Debug] Dispatching email to ${result.targetEmails}`);
      // Background email dispatch
      sendLowStockEmail(
        result.targetEmails,
        result.updatedIngredient.name,
        result.updatedIngredient.currentStock,
        result.updatedIngredient.minStockLevel,
        result.updatedIngredient.unit
      ).then(() => console.log("[Email Debug] sendLowStockEmail function completed its block"))
       .catch(err => console.error("[Email API Error]:", err));
    }

    return NextResponse.json(result);
  } catch (error: any) {
    console.error("Transaction Error:", error);
    const statusCode = error.message === "Unauthorized" ? 403 : 500;
    return NextResponse.json({ error: "Failed to process movement", details: error.message }, { status: statusCode });
  }
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { LogIn, Package, ShieldCheck, Zap, ArrowRight, Eye, EyeOff } from 'lucide-react';
import Link from 'next/link';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';

const slides = [
  {
    title: "Stoklarınızı Akıllıca Yönetin",
    description: "Gerçek zamanlı envanter takibi ile işletmenizin verimliliğini artırın.",
    image: "/assets/images/login-carousel-1.png",
    icon: <Package className="w-5 h-5" />
  },
  {
    title: "Güvenli ve Hızlı Altyapı",
    description: "Tüm verileriniz en üst düzey güvenlik standartlarıyla korunur.",
    image: "/assets/images/login-carousel-2.png",
    icon: <ShieldCheck className="w-5 h-5" />
  }
];

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const router = useRouter();
  const { login } = useAuth();

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    try {
      await login(email, password, rememberMe);
      toast.success('Giriş başarılı! Hoş geldiniz.');
      router.push('/');
    } catch (error: any) {
      toast.error(error.message || 'Giriş yapılamadı, lütfen bilgilerinizi kontrol edin.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen bg-white font-sans selection:bg-indigo-100 overflow-hidden">
      {/* Left Side: Form */}
      <div className="flex flex-col justify-center w-full px-8 py-8 lg:w-[35%] md:px-16 lg:px-20 xl:px-24">
        <motion.div
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.6 }}
          className="mb-8"
        >
          <div className="flex items-center gap-2 mb-4 group cursor-pointer w-fit">
            <div className="p-2 transition-transform duration-300 bg-indigo-600 rounded-lg shadow-lg group-hover:rotate-12">
              <Package size={24} className="text-white" />
            </div>
            <span className="text-xl font-black tracking-tight text-slate-900">Stok<span className="text-indigo-600">Takip</span></span>
          </div>

          <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 mb-2">Tekrar Hoş Geldiniz</h1>
          <p className="text-base text-slate-500 font-medium">Hesabınıza erişmek için bilgilerinizi girin.</p>
        </motion.div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2, duration: 0.5 }}
          >
            <label className="block mb-1 text-sm font-bold text-slate-700">Email Adresiniz</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full px-4 py-2.5 bg-slate-50 border-2 border-slate-100 rounded-xl focus:border-indigo-600 focus:bg-white focus:outline-none transition-all duration-200 text-sm text-slate-800 placeholder:text-slate-400"
              placeholder="isim@sirket.com"
              required
            />
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3, duration: 0.5 }}
          >
            <div className="flex items-center justify-between mb-1">
              <label className="text-sm font-bold text-slate-700">Şifreniz</label>
              <Link href="/forgot-password" className="px-1 text-xs font-bold text-indigo-600 hover:text-indigo-700">
                Şifremi Unuttum
              </Link>
            </div>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full px-4 py-2.5 bg-slate-50 border-2 border-slate-100 rounded-xl focus:border-indigo-600 focus:bg-white focus:outline-none transition-all duration-200 text-sm text-slate-800 placeholder:text-slate-400"
                placeholder="••••••••"
                required
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute text-slate-400 right-4 top-1/2 -translate-y-1/2 hover:text-indigo-600 transition-colors"
              >
                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </motion.div>

          <motion.div
            className="flex items-center gap-2"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
          >
            <input
              type="checkbox"
              id="remember"
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
              className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-600 accent-indigo-600"
            />
            <label htmlFor="remember" className="text-sm font-medium text-slate-500 cursor-pointer">30 gün boyunca beni hatırla</label>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5, duration: 0.5 }}
          >
            <button
              type="submit"
              disabled={isLoading}
              className="relative w-full py-3 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-200 transition-all duration-200 overflow-hidden flex items-center justify-center gap-2 group cursor-pointer"
            >
              {isLoading ? (
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
              ) : (
                <>
                  Giriş Yap
                  <ArrowRight size={18} className="transition-transform group-hover:translate-x-1" />
                </>
              )}
            </button>
          </motion.div>

          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.6 }}
          >
            <button
              type="button"
              className="w-full flex items-center justify-center gap-3 py-2.5 px-4 bg-white border-2 border-slate-100 rounded-xl hover:bg-slate-50 hover:border-slate-200 transition-all duration-200 text-sm font-bold text-slate-700 cursor-pointer"
            >
              <img src="https://www.svgrepo.com/show/475656/google-color.svg" className="h-5 w-5" alt="Google logo" />
              Google ile Giriş Yap
            </button>
          </motion.div>
        </form>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.7 }}
          className="mt-8 text-center text-sm text-slate-500 font-medium"
        >
          Hesabınız yok mu?{' '}
          <Link href="/register" className="font-bold text-indigo-600 hover:text-indigo-700 border-b-2 border-indigo-100 hover:border-indigo-600 transition-all px-0.5">
            Hemen Kayıt Ol
          </Link>
        </motion.p>
      </div>

      {/* Right Side: Carousel */}
      <div className="hidden lg:flex lg:w-[65%] bg-slate-50 relative overflow-hidden items-center justify-center p-12">
        {/* Animated blobs background */}
        <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/2 w-[600px] h-[600px] bg-indigo-100/50 rounded-full blur-3xl animate-pulse" />
        <div className="absolute bottom-0 left-0 translate-y-1/2 -translate-x-1/2 w-[600px] h-[600px] bg-purple-100/50 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '2s' }} />

        <AnimatePresence mode="wait">
          <motion.div
            key={currentSlide}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.6, ease: "easeInOut" }}
            className="relative z-10 w-full max-w-lg px-12 text-center"
          >
            <div className="mb-6 flex justify-center">
              <div className="relative group">
                <div className="absolute inset-0 bg-indigo-500 rounded-3xl blur-3xl opacity-10 group-hover:opacity-20 transition-opacity duration-500" />
                <img
                  src={slides[currentSlide].image}
                  alt={slides[currentSlide].title}
                  className="relative rounded-3xl shadow-2xl object-cover w-full aspect-square max-h-[350px]"
                />
              </div>
            </div>

            <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-indigo-600 text-white rounded-full text-[10px] font-black tracking-widest mb-4 shadow-md shadow-indigo-100 uppercase">
              {slides[currentSlide].icon}
              <span>ÖZELLİK {currentSlide + 1}</span>
            </div>

            <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tight leading-tight">{slides[currentSlide].title}</h2>
            <p className="text-base text-slate-500 leading-relaxed mb-8 font-medium">{slides[currentSlide].description}</p>

            <div className="flex justify-center gap-3">
              {slides.map((_, idx) => (
                <button
                  key={idx}
                  onClick={() => setCurrentSlide(idx)}
                  className={`h-2 rounded-full transition-all duration-300 cursor-pointer ${idx === currentSlide ? 'w-10 bg-indigo-600' : 'w-2 bg-indigo-200 hover:bg-indigo-300'}`}
                />
              ))}
            </div>
          </motion.div>
        </AnimatePresence>
      </div>

    </div>
  );
}

