"use client";

import React, { useEffect, useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { Plus, Settings2, History, FileOutput, FileText, LayoutDashboard } from "lucide-react";
import { exportToExcel, exportToPDF } from "@/lib/exportUtils";
import AddStockModal from "@/components/AddStockModal";
import MovementButtons from "@/components/MovementButtons";
import EditStockModal from "@/components/EditStockModal";
import ActivityLogList from "@/components/ActivityLogList";
import MetricCards from "@/components/MetricCards";
import DashboardCharts from "@/components/DashboardCharts";
import toast from "react-hot-toast";

import { Ingredient } from "@/types";

export default function Home() {
  const router = useRouter();
  const { isAuthenticated, token, isLoading: authLoading } = useAuth();
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [analytics, setAnalytics] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [editingIngredient, setEditingIngredient] = useState<Ingredient | null>(null);
  const [refreshLogsKey, setRefreshLogsKey] = useState(() => Date.now());

  const fetchIngredients = useCallback(() => {
    if (!token) return;

    fetch("/api/ingredients", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => {
        if (res.status === 401) {
          router.push("/login");
          return [];
        }
        return res.json();
      })
      .then((data) => {
        if (Array.isArray(data)) {
          setIngredients(data);
        }
      })
      .catch((err) => {
        console.error("Fetch ingredients error:", err);
      });
  }, [token, router]);

  const fetchAnalytics = useCallback(() => {
    if (!token) return;

    fetch("/api/analytics", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        if (!data.error) {
          setAnalytics(data);
        }
      })
      .catch((err) => {
        console.error("Fetch analytics error:", err);
      });
  }, [token]);

  const loadData = useCallback(() => {
    setIsLoading(true);
    Promise.all([fetchIngredients(), fetchAnalytics()])
      .finally(() => setIsLoading(false));
  }, [fetchIngredients, fetchAnalytics]);

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.push("/login");
    }
  }, [isAuthenticated, authLoading, router]);

  useEffect(() => {
    if (token) {
      loadData();
    }
  }, [token, loadData]);

  const triggerRefresh = () => {
    loadData();
    setRefreshLogsKey(Date.now());
  };

  const handleExportExcel = () => {
    const exportData = ingredients.map(i => ({
      'Malzeme Adı': i.name,
      'Birim': i.unit,
      'Mevcut Stok': i.currentStock,
      'Min. Stok': i.minStockLevel,
      'Durum': i.currentStock <= i.minStockLevel ? 'Kritik' : 'Normal',
      'Kayıt Tarihi': new Date().toLocaleString('tr-TR')
    }));
    exportToExcel(exportData, `Stok_Durumu_${new Date().toISOString().split('T')[0]}`);
    toast.success("Excel dosyası indiriliyor...");
  };

  const handleExportPDF = async () => {
    const columns = [
      { header: 'Malzeme Adı', dataKey: 'name' },
      { header: 'Birim', dataKey: 'unit' },
      { header: 'Mevcut Stok', dataKey: 'currentStock' },
      { header: 'Min. Seviye', dataKey: 'minStockLevel' },
      { header: 'Durum', dataKey: 'status' }
    ];

    const exportData = ingredients.map(i => ({
      ...i,
      status: i.currentStock <= i.minStockLevel ? 'Kritik' : 'Normal'
    }));

    await exportToPDF(
      columns,
      exportData,
      `Stok_Durumu_${new Date().toISOString().split('T')[0]}`,
      "Mevcut Stok Durumu Raporu"
    );
    toast.success("PDF dosyası indiriliyor...");
  };

  if (authLoading || isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-slate-500 font-medium">Dashboard Hazırlanıyor...</p>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) return null;

  return (
    <div className="min-h-screen bg-[#fcfdff] text-slate-900 font-sans selection:bg-indigo-100 selection:text-indigo-900">
      {/* Modals */}
      {isAddModalOpen && (
        <AddStockModal
          onClose={() => setIsAddModalOpen(false)}
          onSuccess={triggerRefresh}
        />
      )}

      {editingIngredient && (
        <EditStockModal
          ingredient={editingIngredient}
          onClose={() => setEditingIngredient(null)}
          onSuccess={triggerRefresh}
        />
      )}

      <main className="max-w-7xl mx-auto p-6 lg:p-10">
        {/* Header */}
        <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between gap-6">
          <div>
            <div className="flex items-center gap-2 text-indigo-600 mb-2">
              <LayoutDashboard size={18} />
              <span className="text-sm font-bold tracking-wider uppercase">Genel Bakış</span>
            </div>
            <h1 className="text-3xl font-black tracking-tight text-slate-800">Hoş Geldiniz!</h1>
            <p className="text-slate-500 mt-1">Stoklarınızın ve tüketim verilerinizin gerçek zamanlı özeti.</p>
          </div>

          <div className="flex items-center gap-3">
            <button
              onClick={handleExportExcel}
              className="flex items-center gap-2 px-4 py-2.5 bg-white hover:bg-emerald-50 text-emerald-700 rounded-2xl font-bold transition-all text-sm border border-slate-100 shadow-sm"
            >
              <FileOutput size={16} />
              Excel
            </button>
            <button
              onClick={handleExportPDF}
              className="flex items-center gap-2 px-4 py-2.5 bg-white hover:bg-rose-50 text-rose-700 rounded-2xl font-bold transition-all text-sm border border-slate-100 shadow-sm"
            >
              <FileText size={16} />
              PDF
            </button>
            <button
              onClick={() => setIsAddModalOpen(true)}
              className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-bold transition-all shadow-lg shadow-indigo-100 active:scale-95 text-sm"
            >
              <Plus size={18} />
              Yeni Ekle
            </button>
          </div>
        </div>

        {/* Metrics Section */}
        {analytics && <MetricCards data={analytics.summary} />}

        {/* Charts Section */}
        {analytics && (
          <DashboardCharts
            trendData={analytics.trend}
            distributionData={analytics.distribution}
          />
        )}

        {/* Table Area (Full Width) */}
        <div className="space-y-12">
          {/* Inventory Table */}
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                Envanter Listesi
                <span className="bg-slate-100 text-slate-500 text-[10px] px-2 py-0.5 rounded-full uppercase tracking-tighter">
                  {ingredients.length} KALEM
                </span>
              </h2>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="bg-slate-50/50 text-slate-500 text-[11px] font-bold uppercase tracking-widest">
                    <th className="px-8 py-4">Malzeme</th>
                    <th className="px-8 py-4">Mevcut</th>
                    <th className="px-8 py-4">Durum</th>
                    <th className="px-8 py-4 text-right">Düzenle</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {ingredients.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="px-8 py-20 text-center text-slate-400 italic">
                        Henüz veri girilmemiş.
                      </td>
                    </tr>
                  ) : (
                    ingredients.map((item) => (
                      <tr key={item.id} className="hover:bg-slate-50/30 transition-colors group">
                        <td className="px-8 py-5">
                          <div>
                            <p className="font-bold text-slate-700">{item.name}</p>
                            <p className="text-[10px] font-bold text-slate-400 tracking-wider">BİRİM: {item.unit.toUpperCase()}</p>
                          </div>
                        </td>
                        <td className="px-8 py-5">
                          <span className="font-mono font-black text-lg text-slate-600">{item.currentStock}</span>
                        </td>
                        <td className="px-8 py-5">
                          {item.currentStock <= item.minStockLevel ? (
                            <span className="inline-flex items-center px-3 py-1 bg-rose-50 text-rose-600 rounded-full text-[10px] font-black uppercase tracking-wider border border-rose-100">
                              Kritik
                            </span>
                          ) : (
                            <span className="inline-flex items-center px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black uppercase tracking-wider border border-emerald-100">
                              Normal
                            </span>
                          )}
                        </td>
                        <td className="px-8 py-5 text-right">
                          <div className="flex items-center justify-end gap-3">
                            <MovementButtons
                              ingredientId={item.id}
                              currentStock={item.currentStock}
                              onSuccess={triggerRefresh}
                            />
                            <button
                              onClick={() => setEditingIngredient(item)}
                              className="p-2.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all border border-transparent hover:border-indigo-100"
                            >
                              <Settings2 size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>

          {/* Activity Logs (Full Width Below) */}
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <History size={20} className="text-indigo-600" />
                Son İşlem Hareketleri
              </h2>
              <button
                onClick={() => router.push('/logs')}
                className="text-xs font-bold text-indigo-600 hover:text-indigo-700 flex items-center gap-1 transition-colors tracking-tighter"
              >
                Tümünü Gör <LayoutDashboard size={14} />
              </button>
            </div>

            <ActivityLogList refreshTrigger={refreshLogsKey} limit={10} />
          </div>
        </div>
      </main>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import { UserPlus, Package, ArrowRight, Eye, EyeOff, Building, Phone, Mail, User, Zap } from 'lucide-react';
import Link from 'next/link';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';

const slides = [
  {
    title: "İşletmenizi Büyütmeye Başlayın",
    description: "Hemen kayıt olun ve stok yönetimi süreçlerinizi dijitalleştirerek zaman kazanın.",
    image: "/assets/images/login-carousel-1.png",
    icon: <UserPlus className="w-5 h-5" />
  },
  {
    title: "Kolay ve Hızlı Entegrasyon",
    description: "Kullanıcı dostu arayüz ve hızlı kurulum ile saniyeler içinde kullanmaya başlayın.",
    image: "/assets/images/login-carousel-2.png",
    icon: <Zap className="w-5 h-5" />
  }
];

export default function RegisterPage() {
  const [formData, setFormData] = useState({
    email: '',
    username: '',
    password: '',
    confirmPassword: '',
    accountName: '',
    accountEmail: '',
    phone: '',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);
  const router = useRouter();
  const { register } = useAuth();

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % slides.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      if (formData.password !== formData.confirmPassword) {
        toast.error('Şifreler uyuşmuyor');
        setIsLoading(false);
        return;
      }

      if (formData.password.length < 6) {
        toast.error('Şifre en az 6 karakter olmalı');
        setIsLoading(false);
        return;
      }

      await register({
        email: formData.email,
        username: formData.username,
        password: formData.password,
        accountName: formData.accountName,
        accountEmail: formData.accountEmail,
        phone: formData.phone,
      });

      toast.success('Kayıt başarılı! Hoş geldiniz');
      router.push('/');
    } catch (error: any) {
      toast.error(error.message || 'Kayıt başarısız');
    } finally {
      setIsLoading(false);
    }
  };

  const inputClassName = "w-full px-4 py-2 bg-slate-50 border-2 border-slate-100 rounded-xl focus:border-indigo-600 focus:bg-white focus:outline-none transition-all duration-200 text-sm text-slate-800 placeholder:text-slate-400";

  return (
    <div className="flex xl:h-screen bg-white font-sans selection:bg-indigo-100 overflow-hidden">
      {/* Left Side: Form */}
      <div className="flex flex-col justify-center w-full px-8 py-0 lg:w-[50%] md:px-16 lg:px-20 overflow-y-auto">
        <div className="max-w-2xl w-full mx-auto pb-0">
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="mb-4 mt-0"
          >
            <div className="flex items-center gap-2 mb-4 group cursor-pointer w-fit">
              <div className="p-2 transition-transform duration-300 bg-indigo-600 rounded-lg shadow-lg group-hover:rotate-12">
                <Package size={24} className="text-white" />
              </div>
              <span className="text-xl font-black tracking-tight text-slate-900">Stok<span className="text-indigo-600">Takip</span></span>
            </div>

            <h1 className="text-3xl font-extrabold tracking-tight text-slate-900 mb-1">Yeni Hesap Oluştur</h1>
            <p className="text-base text-slate-500 font-medium">Sistemimizi kullanmaya başlamak için bilgilerinizi girin.</p>
          </motion.div>

          <form onSubmit={handleSubmit} className="space-y-4">
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2, duration: 0.5 }}
            >
              <h3 className="text-sm font-bold text-indigo-600 mb-3 uppercase tracking-wider">Kullanıcı Bilgileri</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-3">
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Email Adresiniz</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      className={`${inputClassName} pl-10`}
                      placeholder="isim@sirket.com"
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Kullanıcı Adı</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="text"
                      name="username"
                      value={formData.username}
                      onChange={handleChange}
                      className={`${inputClassName} pl-10`}
                      placeholder="kullaniciadi"
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Şifre</label>
                  <div className="relative">
                    <input
                      type={showPassword ? "text" : "password"}
                      name="password"
                      value={formData.password}
                      onChange={handleChange}
                      className={inputClassName}
                      placeholder="••••••••"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute text-slate-400 right-3 top-1/2 -translate-y-1/2 hover:text-indigo-600 transition-colors"
                    >
                      {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Şifre Tekrar</label>
                  <div className="relative">
                    <input
                      type={showConfirmPassword ? "text" : "password"}
                      name="confirmPassword"
                      value={formData.confirmPassword}
                      onChange={handleChange}
                      className={inputClassName}
                      placeholder="••••••••"
                      required
                    />
                    <button
                      type="button"
                      onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                      className="absolute text-slate-400 right-3 top-1/2 -translate-y-1/2 hover:text-indigo-600 transition-colors"
                    >
                      {showConfirmPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>

            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3, duration: 0.5 }}
              className="pt-1"
            >
              <h3 className="text-sm font-bold text-indigo-600 mb-3 uppercase tracking-wider">Hesap Bilgileri</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-3">
                <div className="md:col-span-2">
                  <label className="block mb-1 text-sm font-bold text-slate-700">İşletme/Kişi Adı</label>
                  <div className="relative">
                    <Building className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="text"
                      name="accountName"
                      value={formData.accountName}
                      onChange={handleChange}
                      className={`${inputClassName} pl-10`}
                      placeholder="ABC Gıda Ltd."
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Hesap Email</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="email"
                      name="accountEmail"
                      value={formData.accountEmail}
                      onChange={handleChange}
                      className={`${inputClassName} pl-10`}
                      placeholder="info@isletme.com"
                      required
                    />
                  </div>
                </div>
                <div>
                  <label className="block mb-1 text-sm font-bold text-slate-700">Telefon <span className="text-slate-400 font-normal">(İsteğe bağlı)</span></label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                    <input
                      type="tel"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      className={`${inputClassName} pl-10`}
                      placeholder="+90 (555) 123 45 67"
                    />
                  </div>
                </div>
              </div>
            </motion.div>

            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.5, duration: 0.5 }}
              className="pt-1"
            >
              <motion.button
                whileHover={{ scale: 1.01 }}
                whileTap={{ scale: 0.98 }}
                type="submit"
                disabled={isLoading}
                className="relative w-full py-3 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-200 transition-all duration-200 overflow-hidden flex items-center justify-center gap-2 group cursor-pointer"
              >
                {isLoading ? (
                  <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                ) : (
                  <>
                    Kayıt Ol
                    <ArrowRight size={18} className="transition-transform group-hover:translate-x-1" />
                  </>
                )}
              </motion.button>
            </motion.div>
          </form>

          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.7 }}
            className="mt-6 text-center text-sm text-slate-500 font-medium"
          >
            Zaten hesabınız var mı?{' '}
            <Link href="/login" className="font-bold text-indigo-600 hover:text-indigo-700 border-b-2 border-indigo-100 hover:border-indigo-600 transition-all px-0.5">
              Giriş Yap
            </Link>
          </motion.p>
        </div>
      </div>

      {/* Right Side: Carousel */}
      <div className="hidden lg:flex lg:w-[55%] bg-slate-50 relative overflow-hidden items-center justify-center p-12 sticky top-0 h-screen">
        {/* Animated blobs background */}
        <div className="absolute top-0 right-0 -translate-y-1/2 translate-x-1/2 w-[600px] h-[600px] bg-indigo-100/50 rounded-full blur-3xl animate-pulse" />
        <div className="absolute bottom-0 left-0 translate-y-1/2 -translate-x-1/2 w-[600px] h-[600px] bg-purple-100/50 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '2s' }} />

        <AnimatePresence mode="wait">
          <motion.div
            key={currentSlide}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.6, ease: "easeInOut" }}
